WITH all_data AS (
    SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevenue" AS revenue, "totfuncexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_2012" WHERE "tax_pd" IS NOT NULL AND "totrevenue" IS NOT NULL AND "totfuncexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevenue" AS revenue, "totfuncexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_2013" WHERE "tax_pd" IS NOT NULL AND "totrevenue" IS NOT NULL AND "totfuncexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevenue" AS revenue, "totfuncexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_2014" WHERE "tax_pd" IS NOT NULL AND "totrevenue" IS NOT NULL AND "totfuncexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevenue" AS revenue, "totfuncexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_2015" WHERE "tax_pd" IS NOT NULL AND "totrevenue" IS NOT NULL AND "totfuncexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevenue" AS revenue, "totfuncexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_2016" WHERE "tax_pd" IS NOT NULL AND "totrevenue" IS NOT NULL AND "totfuncexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevenue" AS revenue, "totfuncexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_2017" WHERE "tax_pd" IS NOT NULL AND "totrevenue" IS NOT NULL AND "totfuncexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevnue" AS revenue, "totexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_EZ_2012" WHERE "tax_pd" IS NOT NULL AND "totrevnue" IS NOT NULL AND "totexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevnue" AS revenue, "totexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_EZ_2013" WHERE "tax_pd" IS NOT NULL AND "totrevnue" IS NOT NULL AND "totexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevnue" AS revenue, "totexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_EZ_2014" WHERE "tax_pd" IS NOT NULL AND "totrevnue" IS NOT NULL AND "totexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevnue" AS revenue, "totexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_EZ_2015" WHERE "tax_pd" IS NOT NULL AND "totrevnue" IS NOT NULL AND "totexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevnue" AS revenue, "totexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_EZ_2016" WHERE "tax_pd" IS NOT NULL AND "totrevnue" IS NOT NULL AND "totexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT CAST(SUBSTR("tax_pd", 1, 4) AS INTEGER) AS year, "totrevnue" AS revenue, "totexpns" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_EZ_2017" WHERE "tax_pd" IS NOT NULL AND "totrevnue" IS NOT NULL AND "totexpns" IS NOT NULL AND SUBSTR("tax_pd", 1, 4) BETWEEN '2012' AND '2017'
    UNION ALL SELECT "tax_yr" AS year, "totrcptperbks" AS revenue, "totexpnspbks" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_PF_2012" WHERE "tax_yr" IS NOT NULL AND "totrcptperbks" IS NOT NULL AND "totexpnspbks" IS NOT NULL AND "tax_yr" BETWEEN 2012 AND 2017
    UNION ALL SELECT "tax_yr" AS year, "totrcptperbks" AS revenue, "totexpnspbks" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_PF_2013" WHERE "tax_yr" IS NOT NULL AND "totrcptperbks" IS NOT NULL AND "totexpnspbks" IS NOT NULL AND "tax_yr" BETWEEN 2012 AND 2017
    UNION ALL SELECT "tax_yr" AS year, "totrcptperbks" AS revenue, "totexpnspbks" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_PF_2014" WHERE "tax_yr" IS NOT NULL AND "totrcptperbks" IS NOT NULL AND "totexpnspbks" IS NOT NULL AND "tax_yr" BETWEEN 2012 AND 2017
    UNION ALL SELECT "tax_yr" AS year, "totrcptperbks" AS revenue, "totexpnspbks" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_PF_2015" WHERE "tax_yr" IS NOT NULL AND "totrcptperbks" IS NOT NULL AND "totexpnspbks" IS NOT NULL AND "tax_yr" BETWEEN 2012 AND 2017
    UNION ALL SELECT "tax_yr" AS year, "totrcptperbks" AS revenue, "totexpnspbks" AS expenses FROM "IRS_990"."IRS_990"."IRS_990_PF_2016" WHERE "tax_yr" IS NOT NULL AND "totrcptperbks" IS NOT NULL AND "totexpnspbks" IS NOT NULL AND "tax_yr" BETWEEN 2012 AND 2017
)
SELECT year, ABS(MEDIAN(revenue) - MEDIAN(expenses)) AS diff FROM all_data GROUP BY year ORDER BY diff ASC LIMIT 3